### 5. Test 스킬 (test-skill/SKILL.md)

**테스트 구조**:

```kotlin
// 단위 테스트
@ExtendWith(MockitoExtension::class)
class ChatServiceTest {
    @Mock
    private lateinit var repository: ChatMessageRepository

    @InjectMocks
    private lateinit var service: ChatService

    @Test
    fun `should save chat image successfully`() {
        // given
        val entity = ChatImageEntity(messageId = "msg-1", url = "https://...")
        `when`(repository.save(any())).thenReturn(entity)

        // when
        val result = service.uploadImage("msg-1", "https://...")

        // then
        assertThat(result.url).isEqualTo("https://...")
        verify(repository).save(any())
    }
}

// gRPC Service 테스트
@ExtendWith(MockitoExtension::class)
class ChatGrpcServiceTest {
    @Test
    fun `should send image via gRPC`() {
        val responseObserver = mock<StreamObserver<SendImageResponse>>()
        grpcService.sendImage(request, responseObserver)
        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
    }
}

// Repository 통합 테스트
@DataJpaTest
class ChatImageRepositoryTest {
    @Autowired
    private lateinit var repository: ChatImageRepository

    @Test
    fun `should find images by room id`() {
        // given
        val entity = ChatImageEntity(roomId = "room-1", url = "...")
        repository.save(entity)

        // when
        val result = repository.findByRoomId("room-1")

        // then
        assertThat(result).hasSize(1)
    }
}
```

