./gradlew :chat:build -x test          # Chat 모듈만
./gradlew :protobuf:clean :protobuf:build  # Proto 재생성
./gradlew :chat:test                   # Chat 테스트
./gradlew :chat:compileKotlin          # 컴파일만
```

